<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;from</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;john@doe.com&quot;</span></span>
